import React, { useCallback, useMemo } from 'react';
import { FormMode, isEditingMode } from '../form/FormMode';
import { ToolbarResponsiveRow } from './ToolbarResponsiveRow';
import type { ToolbarOverflowItem } from './ToolbarOverflowMenu';
import { useToolbarNarrowLayout } from './useToolbarNarrowLayout';
import styles from './VoucherFormToolbar.module.css';

/** @deprecated Use FormMode from `components/form` */
export type VoucherFormMode = FormMode;

/** Tooltip khi nút disabled — `title` hiển thị lý do (hover). */
export interface VoucherToolbarDisabledReasons {
  approve?: string;
  post?: string;
  copy?: string;
  print?: string;
  history?: string;
  edit?: string;
  delete?: string;
  save?: string;
}

function toolbarButtonTitle(enabled: boolean, enabledTitle: string, disabledReason?: string): string {
  if (!enabled && disabledReason?.trim()) return disabledReason.trim();
  return enabledTitle;
}

export interface VoucherFormToolbarProps {
  testIdPrefix: string;
  title: string;
  /** Pill Mức xử lý — `VoucherFormStatusGroup`. Cấm badge `status` / `VoucherStatusBadge`. */
  processingLevelBadge?: React.ReactNode;
  formMode: FormMode;
  showViewHint?: boolean;
  canApprove?: boolean;
  /** false — không render nút Phê duyệt (thiếu quyền). Default: true trong view mode. */
  showApproveButton?: boolean;
  canPost?: boolean;
  /** false — không render nút Ghi sổ (mức xử lý 9). */
  showPostButton?: boolean;
  canCopy?: boolean;
  canPrint?: boolean;
  canHistory?: boolean;
  canEdit?: boolean;
  canDelete?: boolean;
  /** false — disable nút Lưu (thiếu quyền create/update). Default true. */
  canSave?: boolean;
  /** false — ẩn nút Sửa (rule: đã phê duyệt / không Draft). Default true. */
  showEditButton?: boolean;
  /** false — ẩn nút Xóa. Default true. */
  showDeleteButton?: boolean;
  saving?: boolean;
  posting?: boolean;
  saveLabel?: string;
  searchNav?: {
    index: number;
    total: number;
    onFirst: () => void;
    onPrev: () => void;
    onNext: () => void;
    onEnd: () => void;
  };
  onBack: () => void;
  onApprove: () => void;
  onPost: () => void;
  onCopy: () => void;
  onPrint: () => void;
  onHistory?: () => void;
  onSearch: () => void;
  onNew: () => void;
  onEdit: () => void;
  onSave: () => void;
  onCancel: () => void;
  onDelete: () => void;
  /** Lý do disable — hiển thị qua `title` khi hover (rule `voucher-form-toolbar.md`). */
  disabledReasons?: VoucherToolbarDisabledReasons;
  /** Padding/card đồng bộ `pageFormHeader` / footer inset (voucher full-page). */
  insetShell?: boolean;
  /** Hiển thị nút Xem sổ cái (dữ liệu đã post). */
  canViewLedger?: boolean;
  onViewLedger?: () => void;
}

const DETAIL_ACTIONS_MAX_VISIBLE = 3;

export const VoucherFormToolbar: React.FC<VoucherFormToolbarProps> = ({
  testIdPrefix,
  title,
  processingLevelBadge,
  formMode,
  showViewHint,
  canApprove = false,
  showApproveButton = true,
  canPost = false,
  showPostButton = true,
  canCopy = false,
  canPrint = false,
  canHistory = false,
  canEdit = false,
  canDelete = false,
  canSave = true,
  showEditButton = true,
  showDeleteButton = true,
  saving = false,
  posting = false,
  saveLabel = 'Lưu',
  searchNav,
  onBack,
  onApprove,
  onPost,
  onCopy,
  onPrint,
  onHistory,
  onSearch,
  onNew,
  onEdit,
  onSave,
  onCancel,
  onDelete,
  disabledReasons,
  insetShell = false,
  canViewLedger = false,
  onViewLedger,
}) => {
  const tid = (s: string) => `${testIdPrefix}-toolbar-${s}`;
  const isEditing = isEditingMode(formMode);
  const narrow = useToolbarNarrowLayout();
  const hasNav = !isEditing && searchNav && searchNav.total > 0;
  const navAtStart = hasNav && searchNav!.index <= 0;
  const navAtEnd = hasNav && searchNav!.index >= searchNav!.total - 1;

  const renderBackButton = useCallback(() => (
    <button
      type="button"
      className={styles.toolbarBtn}
      data-testid={tid('back')}
      onClick={onBack}
    >
      <i className="fas fa-arrow-left" aria-hidden /> Quay lại
    </button>
  ), [onBack, testIdPrefix]);

  const commonViewItems = useMemo((): ToolbarOverflowItem[] => {
    const items: ToolbarOverflowItem[] = [{ key: 'back', node: renderBackButton() }];

    if (showApproveButton) {
      items.push({
        key: 'approve',
        node: (
          <button
            type="button"
            className={styles.toolbarBtn}
            data-testid={tid('approve')}
            onClick={onApprove}
            disabled={!canApprove}
            title={toolbarButtonTitle(
              !!canApprove,
              'Phê duyệt — cập nhật mức xử lý',
              disabledReasons?.approve,
            )}
          >
            <i className="fas fa-check-double" aria-hidden /> Phê duyệt
          </button>
        ),
      });
    }

    if (showPostButton) {
      items.push({
        key: 'post',
        node: (
          <button
            type="button"
            className={styles.toolbarBtn}
            data-testid={tid('post')}
            onClick={onPost}
            disabled={!canPost || posting}
            title={toolbarButtonTitle(
              !!(canPost && !posting),
              'Ghi sổ chứng từ',
              disabledReasons?.post,
            )}
          >
            <i className={`fas ${posting ? 'fa-spinner fa-spin' : 'fa-book'}`} aria-hidden /> Ghi sổ
          </button>
        ),
      });
    }

    if (canViewLedger) {
      items.push({
        key: 'view-ledger',
        node: (
          <button
            type="button"
            className={styles.toolbarBtn}
            data-testid={tid('view-ledger')}
            onClick={onViewLedger}
            title="Xem dữ liệu đã ghi lên sổ cái"
          >
            <i className="fas fa-table-list" aria-hidden /> Xem sổ cái
          </button>
        ),
      });
    }

    items.push(
      {
        key: 'copy',
        node: (
          <button
            type="button"
            className={styles.toolbarBtn}
            data-testid={tid('copy')}
            onClick={onCopy}
            disabled={!canCopy}
            title={toolbarButtonTitle(!!canCopy, 'Sao chép chứng từ', disabledReasons?.copy)}
          >
            <i className="fas fa-copy" aria-hidden /> Copy
          </button>
        ),
      },
      {
        key: 'print',
        node: (
          <button
            type="button"
            className={styles.toolbarBtn}
            data-testid={tid('print')}
            onClick={onPrint}
            disabled={!canPrint}
            title={toolbarButtonTitle(!!canPrint, 'In chứng từ', disabledReasons?.print)}
          >
            <i className="fas fa-print" aria-hidden /> In
          </button>
        ),
      },
    );

    if (onHistory) {
      items.push({
        key: 'history',
        node: (
          <button
            type="button"
            className={styles.toolbarBtn}
            data-testid={tid('history')}
            onClick={onHistory}
            disabled={!canHistory}
            title={toolbarButtonTitle(
              !!canHistory,
              'Lịch sử thao tác và thay đổi',
              disabledReasons?.history,
            )}
          >
            <i className="fas fa-history" aria-hidden /> Lịch sử
          </button>
        ),
      });
    }

    items.push({
      key: 'search',
      node: (
        <button
          type="button"
          className={styles.toolbarBtn}
          data-testid={tid('search')}
          onClick={onSearch}
          title="Tìm kiếm chứng từ"
        >
          <i className="fas fa-search" aria-hidden /> Tìm kiếm
        </button>
      ),
    });

    if (hasNav) {
      items.push({
        key: 'search-nav',
        node: (
          <div className={styles.navGroup} data-testid={tid('search-nav')}>
            <button
              type="button"
              className={styles.navBtn}
              data-testid={tid('search-first')}
              onClick={searchNav!.onFirst}
              disabled={navAtStart}
              title="Chứng từ đầu"
            >
              <i className="fas fa-angle-double-left" aria-hidden />
            </button>
            <button
              type="button"
              className={styles.navBtn}
              data-testid={tid('search-prev')}
              onClick={searchNav!.onPrev}
              disabled={navAtStart}
              title="Chứng từ trước"
            >
              <i className="fas fa-angle-left" aria-hidden />
            </button>
            <span className={styles.navPosition} data-testid={tid('search-position')}>
              {searchNav!.index + 1}/{searchNav!.total}
            </span>
            <button
              type="button"
              className={styles.navBtn}
              data-testid={tid('search-next')}
              onClick={searchNav!.onNext}
              disabled={navAtEnd}
              title="Chứng từ sau"
            >
              <i className="fas fa-angle-right" aria-hidden />
            </button>
            <button
              type="button"
              className={styles.navBtn}
              data-testid={tid('search-end')}
              onClick={searchNav!.onEnd}
              disabled={navAtEnd}
              title="Chứng từ cuối"
            >
              <i className="fas fa-angle-double-right" aria-hidden />
            </button>
          </div>
        ),
      });
    }

    return items;
  }, [
    renderBackButton,
    showApproveButton,
    showPostButton,
    canViewLedger,
    onHistory,
    hasNav,
    canApprove,
    canPost,
    posting,
    canCopy,
    canPrint,
    canHistory,
    navAtStart,
    navAtEnd,
    searchNav,
    disabledReasons,
    onApprove,
    onPost,
    onViewLedger,
    onCopy,
    onPrint,
    onSearch,
    testIdPrefix,
  ]);

  const line1TrailingPrimaryKeys = useMemo((): string[] => {
    if (showApproveButton) return ['approve'];
    if (canViewLedger) return ['view-ledger'];
    return [];
  }, [showApproveButton, canViewLedger]);

  const detailViewItems = useMemo((): ToolbarOverflowItem[] => {
    const items: ToolbarOverflowItem[] = [
      {
        key: 'new',
        node: (
          <button
            type="button"
            className={styles.toolbarBtn}
            data-testid={tid('new')}
            onClick={onNew}
            title="Tạo chứng từ mới"
          >
            <i className="fas fa-plus" aria-hidden /> Tạo mới
          </button>
        ),
      },
    ];

    if (showEditButton) {
      items.push({
        key: 'edit',
        node: (
          <button
            type="button"
            className={styles.toolbarBtn}
            data-testid={tid('edit')}
            onClick={onEdit}
            disabled={!canEdit}
            title={toolbarButtonTitle(!!canEdit, 'Sửa chứng từ', disabledReasons?.edit)}
          >
            <i className="fas fa-edit" aria-hidden /> Sửa
          </button>
        ),
      });
    }

    if (showDeleteButton) {
      items.push({
        key: 'delete',
        node: (
          <button
            type="button"
            className={styles.toolbarBtnDanger}
            data-testid={tid('delete')}
            onClick={onDelete}
            disabled={!canDelete}
            title={toolbarButtonTitle(!!canDelete, 'Xóa chứng từ', disabledReasons?.delete)}
          >
            <i className="fas fa-trash-alt" aria-hidden /> Xóa
          </button>
        ),
      });
    }

    return items;
  }, [
    showEditButton,
    showDeleteButton,
    canEdit,
    canDelete,
    disabledReasons,
    onNew,
    onEdit,
    onDelete,
    testIdPrefix,
  ]);

  const editDetailItems = useMemo((): ToolbarOverflowItem[] => [
    {
      key: 'cancel',
      node: (
        <button
          type="button"
          className={styles.toolbarBtn}
          data-testid={tid('cancel')}
          onClick={onCancel}
          disabled={saving}
          title="Hủy thay đổi"
        >
          <i className="fas fa-times" aria-hidden /> Hủy
        </button>
      ),
    },
    {
      key: 'save',
      node: (
        <button
          type="button"
          className={styles.toolbarBtnPrimary}
          data-testid={tid('save')}
          onClick={onSave}
          disabled={saving || !canSave}
          title={toolbarButtonTitle(!!canSave && !saving, 'Lưu chứng từ', disabledReasons?.save)}
        >
          <i className={`fas ${saving ? 'fa-spinner fa-spin' : 'fa-save'}`} aria-hidden /> {saveLabel}
        </button>
      ),
    },
  ], [saving, canSave, saveLabel, disabledReasons, onCancel, onSave, testIdPrefix]);

  const commonWithoutBack = useMemo(
    () => commonViewItems.filter((item) => item.key !== 'back'),
    [commonViewItems],
  );

  return (
    <>
      <div
        className={[
          styles.toolbarStack,
          isEditing || !narrow ? styles.toolbarStackSingle : styles.toolbarStackTwoRows,
          insetShell ? styles.toolbarInsetStack : '',
        ].filter(Boolean).join(' ')}
        data-testid={tid('bar')}
      >
        {isEditing ? (
          <ToolbarResponsiveRow
            rowTestId={tid('edit-bar')}
            testIdPrefix={testIdPrefix}
            layout="edit"
            pinnedKeys={['back']}
            items={[
              { key: 'back', node: renderBackButton() },
              ...editDetailItems,
            ]}
            maxVisible={DETAIL_ACTIONS_MAX_VISIBLE}
          />
        ) : !narrow ? (
          <div className={styles.toolbarRowSingle} data-testid={tid('single-row')}>
            {renderBackButton()}
            <div className={styles.toolbarCommonCluster} data-testid={tid('left')}>
              {commonWithoutBack.map((item) => (
                <React.Fragment key={item.key}>{item.node}</React.Fragment>
              ))}
            </div>
            <div className={styles.toolbarRightCluster} data-testid={tid('right')}>
              {detailViewItems.map((item) => (
                <React.Fragment key={item.key}>{item.node}</React.Fragment>
              ))}
            </div>
          </div>
        ) : (
          <>
            <ToolbarResponsiveRow
              rowTestId={tid('left')}
              rowClassName={styles.toolbarRowLine1}
              testIdPrefix={testIdPrefix}
              items={commonViewItems}
              maxVisible={commonViewItems.length}
              layout="common"
              pinnedKeys={['back']}
              trailingPrimaryKeys={line1TrailingPrimaryKeys}
              narrow={narrow}
            />
            <ToolbarResponsiveRow
              rowTestId={tid('right')}
              testIdPrefix={testIdPrefix}
              items={detailViewItems}
              maxVisible={DETAIL_ACTIONS_MAX_VISIBLE}
              layout="detail"
            />
          </>
        )}
      </div>

      <div className={[styles.titleBlock, insetShell ? styles.titleBlockInset : ''].filter(Boolean).join(' ')}>
        <div className={styles.titleRow}>
          <h1 className={styles.title} data-testid={tid('title')}>{title}</h1>
          {processingLevelBadge}
        </div>
        {showViewHint && formMode === FormMode.View && (
          <div className={styles.viewModeHint} data-testid={tid('view-hint')}>
            <i className="fas fa-eye" aria-hidden /> Chế độ xem — nhấn <strong>Sửa</strong> để chỉnh sửa
          </div>
        )}
        {isEditing && (
          <div className={styles.readOnlyHint} data-testid={tid('edit-hint')}>
            <i className="fas fa-pen" aria-hidden /> Đang {formMode === FormMode.Create ? 'tạo mới' : 'chỉnh sửa'} — Lưu hoặc Hủy
          </div>
        )}
      </div>
    </>
  );
};
